# MENU SCREEN
# ============================================================
def drawMenuScreen(app):
    drawPokerTableBackground(app)
    
    # Title banner background (pixelated banner shape)
    drawRect(120, 100, 560, 60, fill=rgb(140, 20, 20))
    drawRect(124, 104, 552, 52, fill=rgb(180, 30, 30))
    # Pixel border effect on banner
    drawRect(120, 100, 560, 4, fill=rgb(200, 160, 50))
    drawRect(120, 156, 560, 4, fill=rgb(200, 160, 50))
    drawRect(120, 100, 4, 60, fill=rgb(200, 160, 50))
    drawRect(676, 100, 4, 60, fill=rgb(200, 160, 50))
    
    # Title text
    drawPixelText('WELCOME TO CARD GAME SUITE', app.width / 2, 130, 
                  rgb(255, 230, 150), scale=1.5)
    
    # Subtitle
    drawPixelText('please select a game below!', app.width / 2, 195, 
                  rgb(200, 200, 180), scale=1)
    
    # Decorative chip icons next to subtitle
    drawPixelChip(app.width/2 - 180, 188, rgb(200, 50, 50))
    drawPixelChip(app.width/2 + 168, 188, rgb(50, 50, 200))

    # Decorative cards scattered around the title
    drawMiniCard(135, 115, 'heart')
    drawMiniCard(165, 115, 'spade')
    drawMiniCard(605, 115, 'diamond')
    drawMiniCard(635, 115, 'club')
    
    # Footer text
    drawPixelText('press R for rules', app.width / 2, 535, 
                  rgb(150, 150, 130), scale=0.8)
    
    # Decorative bottom cards
    # Bottom left
    drawMiniCard(80, 480, 'club')
    drawMiniCard(110, 490, 'heart')

    # Bottom right (mirrored)
    drawMiniCard(app.width - 132, 490, 'diamond')
    drawMiniCard(app.width - 102, 480, 'spade')

def drawPixelChip(x, y, color):
    # Simple 8-bit poker chip (circle made of squares)
    drawRect(x + 4, y, 8, 4, fill=color)
    drawRect(x, y + 4, 16, 8, fill=color)
    drawRect(x + 4, y + 12, 8, 4, fill=color)
    # Center dot
    drawRect(x + 6, y + 6, 4, 4, fill='white')